    protected ReActTrace getTrace(FlowContext context, Prompt prompt) {
        ReActTrace trace = context.getAs(config.getTraceKey());
        if (trace == null) {
            trace = new ReActTrace(prompt);
            context.put(config.getTraceKey(), trace);
        }
        return trace;
